import{_ as e,o as i,c as s,ae as t}from"./chunks/framework.D7zHIyZF.js";const u=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{"title":"Quick Start"},"headers":[],"relativePath":"quick-start.md","filePath":"quick-start.md"}'),o={name:"quick-start.md"};function n(r,a,l,d,c,h){return i(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Linux 6.13 or later</li><li>jai <a href="/install.html">installed</a> (setuid root or invoked via <code>sudo</code>)</li></ul><h2 id="recommended-first-run-setup" tabindex="-1">Recommended first-run setup <a class="header-anchor" href="#recommended-first-run-setup" aria-label="Permalink to &quot;Recommended first-run setup&quot;">​</a></h2><p>You can start using <code>jai</code> immediately; it creates default configuration files on first use. Still, it is usually a good idea to create them explicitly before your first real sandbox so you can inspect the defaults:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --init</span></span></code></pre></div><p>This populates <code>$HOME/.jai/</code> with a <code>.defaults</code> file containing sensible blacklists for sensitive dotfiles (<code>.ssh</code>, <code>.gnupg</code>, etc.) and environment variables (tokens, keys, passwords). You may want to look at and edit <code>$HOME/.jai/.defaults</code>. If your home directory is on a network file system, uncomment the <code>storage</code> line in <code>$HOME/.jai/.defaults</code> and point it to a directory you can write on a local file system.</p><h2 id="launch-a-jailed-shell" tabindex="-1">Launch a jailed shell <a class="header-anchor" href="#launch-a-jailed-shell" aria-label="Permalink to &quot;Launch a jailed shell&quot;">​</a></h2><p>With no arguments, jai drops you into a sandboxed shell:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/my-vibecoded-project</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span></span></code></pre></div><p>Inside the jail:</p><ul><li>Software has full read/write access to the <strong>current working directory</strong> in which you ran jai.</li><li>Your <strong>home directory</strong> is a copy-on-write overlay — changes are stored in <code>$HOME/.jai/default.changes</code> and do not affect your real home.</li><li><strong><code>/tmp</code></strong> and <strong><code>/var/tmp</code></strong> are private. (Outside the jail you can access the private <code>/tmp</code> directory as <code>/run/jai/$USER/tmp/default</code>.)</li><li><strong>Everything else</strong> on the file system is read-only (though devices remain read-write).</li><li>Processes inside the jail have a <strong>private PID namespace</strong> and cannot kill or ptrace processes outside the jail</li></ul><p>Type <code>exit</code> to leave the jail.</p><p>Note: if you run <code>jai</code> in your home directory it will refuse to grant all of your files to the sandbox. You can run <code>jai -D</code> to avoid granting the current working directory.</p><h2 id="run-a-command" tabindex="-1">Run a command <a class="header-anchor" href="#run-a-command" aria-label="Permalink to &quot;Run a command&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex</span></span></code></pre></div><p>This runs <code>codex</code> inside the default casual sandbox. If no command is given, jai starts a shell; if a command is given, jai directly runs the command.</p><h2 id="grant-extra-directories" tabindex="-1">Grant extra directories <a class="header-anchor" href="#grant-extra-directories" aria-label="Permalink to &quot;Grant extra directories&quot;">​</a></h2><p>To grant jailed process write access to additional directories:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /local/build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> your-tool</span></span></code></pre></div><p>You can pass <code>-d</code> multiple times. You must own the directories you grant.</p><h2 id="suppress-automatic-cwd-access" tabindex="-1">Suppress automatic cwd access <a class="header-anchor" href="#suppress-automatic-cwd-access" aria-label="Permalink to &quot;Suppress automatic cwd access&quot;">​</a></h2><p>By default, jai grants access to your current working directory. To suppress this:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -D</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span></span></code></pre></div><p>With <code>-D</code> and no <code>-d</code> flags, your entire home is either copy-on-write (casual) or empty (strict/bare), and nothing is directly exported.</p><h2 id="named-jails" tabindex="-1">Named jails <a class="header-anchor" href="#named-jails" aria-label="Permalink to &quot;Named jails&quot;">​</a></h2><p>Named jails give each tool its own isolated home directory:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span></span></code></pre></div><p>This creates (or reuses) a jail named <code>claude</code>. Named jails default to <strong>strict mode</strong> when they are created — meaning the jailed program runs as the unprivileged <code>jai</code> user with an empty home directory. Granted directories are exposed via id-mapped mounts.</p><p>If the <code>jai</code> system user does not exist or if your home directory is on NFS, jai will be unable to run in strict mode, and you will need to specify bare mode with <code>-mbare</code>.</p><p>You can also use casual mode with named jails, as in:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mcasual</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span></span></code></pre></div><p>The default mode for a jail is set in the corresponding <code>.jai</code> file, e.g., <code>$HOME/.jai/claude.jail</code>.</p><p>If you want a newly created strict or bare jail to start with dotfiles or tool-specific state, add an <code>initjail</code> directive to the relevant config file. See <a href="/configuration.html">Configuration</a> for details and <a href="/recipes.html">Recipes</a> for an example.</p><h2 id="tear-down" tabindex="-1">Tear down <a class="header-anchor" href="#tear-down" aria-label="Permalink to &quot;Tear down&quot;">​</a></h2><p>To unmount all overlays and clean up temporary state:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span></span></code></pre></div><p>This destroys private <code>/tmp</code> directories and removes overlay work files. Run this when you want a fresh start or before making any modifications to overlay change directories.</p><p>To tear down just one named jail instead of all of them, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/modes.html">Modes</a> — understand casual, strict, and bare mode</li><li><a href="/configuration.html">Configuration</a> — config files and per-command settings</li><li><a href="/recipes.html">Recipes</a> — practical examples for Claude Code, Codex, and more</li></ul>`,42)])])}const k=e(o,[["render",n]]);export{u as __pageData,k as default};
